const body = $json.body || $json;
const targetMonth = body.target_month || new Date().toISOString().slice(0, 7);
const batchId = body.batch_id || `batch-${Date.now()}`;
const counts = body.requested_counts || { instagram: 10, x: 8, tiktok: 8, facebook: 6, linkedin: 6 };
const platforms = ['instagram', 'x', 'tiktok', 'facebook', 'linkedin'];
const rows = [];
for (const platform of platforms) {
  const amount = Number(counts[platform] || 0);
  for (let i = 0; i < amount; i += 1) {
    rows.push({
      batch_id: batchId,
      target_month: targetMonth,
      platform,
      post_type: i % 3 === 0 ? 'video' : i % 3 === 1 ? 'image' : 'carousel',
      subject_title: `${platform.toUpperCase()} topic ${i + 1}`,
      five_hooks: [
        `Hook 1 for ${platform} ${i + 1}`,
        `Hook 2 for ${platform} ${i + 1}`,
        `Hook 3 for ${platform} ${i + 1}`,
        `Hook 4 for ${platform} ${i + 1}`,
        `Hook 5 for ${platform} ${i + 1}`
      ],
      content_instagram: platform === 'instagram' ? `Instagram copy ${i + 1}` : null,
      content_x: platform === 'x' ? `X copy ${i + 1}` : null,
      content_tiktok: platform === 'tiktok' ? `TikTok copy ${i + 1}` : null,
      content_facebook: platform === 'facebook' ? `Facebook copy ${i + 1}` : null,
      content_linkedin: platform === 'linkedin' ? `LinkedIn copy ${i + 1}` : null,
      caption_text: `Caption for ${platform} ${i + 1}`,
      blog_article: `Blog brief for ${platform} ${i + 1}`,
      newsletter_text: `Newsletter snippet for ${platform} ${i + 1}`,
      competitor_keywords: [`${platform} keyword`, 'competitor angle'],
      recommended_hashtags: ['#ziyadasystem', '#businessgrowth', '#marketing'],
      banana_image_prompt: `Banana-style image prompt for ${platform} ${i + 1}`,
      video_generator_prompt: `Video generation prompt for ${platform} ${i + 1}`
    });
  }
}
return { batch_id: batchId, target_month: targetMonth, rows, summary: `Generated ${rows.length} calendar items` };
